const weatherApp = {
  apiKey: 'MOCK_KEY',
  async fetchWeather(city) {
    const response = await fetch(`https://api.example.com/weather?q=${city}`);
    if (!response.ok) return alert('City not found');
    const data = await response.json();
    this.displayWeather(data);
  },
  displayWeather(data) {
    const { name, main: { temp }, weather } = data;
    document.querySelector('#city').textContent = name;
    document.querySelector('#temp').textContent = `${temp}°C`;
    document.querySelector('#desc').textContent = weather[0].description;
  }
};

// Triggering the app
weatherApp.fetchWeather('London');

